package main

import "fmt"

type BookInfo struct {
	Title         string
	IsCheckedOut  bool
	PageCount     int
}

func checkOutCopy(b BookInfo) {
	b.IsCheckedOut = true
}

func checkOutPointer(b *BookInfo) {
	b.IsCheckedOut = true
}

func main() {
	b1 := BookInfo{Title: "Go in Action", IsCheckedOut: false, PageCount: 350}
	checkOutCopy(b1)
	fmt.Println("After copy - checked out?:", b1.IsCheckedOut)

	b2 := BookInfo{Title: "Go in Action", IsCheckedOut: false, PageCount: 350}
	checkOutPointer(&b2)
	fmt.Println("After pointer - checked out?:", b2.IsCheckedOut)
}

